"""
mkt-original layer: Joshua 6–8.
88 verses: ch 6 (27), ch 7 (26), ch 8 (35).
Key terms: cherem (ban/devotion to destruction), ma'al (breach of faith),
chamad (covet — 10th commandment verb), tel olam (permanent ruin),
gerim (resident aliens included at Ebal covenant renewal).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "6": {
    "1": "<p><strong>viYricho sogeret umusegeret</strong>: &lsquo;Jericho was shut up and barred&rsquo; — the doubled construction (<em>sogeret</em> participle + <em>musegeret</em> passive) is emphatic: utterly closed, impenetrably locked. The city that no human force could open is the very city YHWH declares already given (<em>natatih</em>) in v2 — a divine perfect treating the future as accomplished fact. The gap between the city&rsquo;s locked state and YHWH&rsquo;s already-given declaration frames the entire chapter as a lesson in what faith receives that sight cannot yet see.</p>",
    "2": "<p><strong>reeh natatih beyadecha</strong>: &lsquo;See — I have given it into your hand&rsquo; — the Hebrew perfect (<em>natatih</em>) is past tense: YHWH speaks of Jericho&rsquo;s fall as already accomplished. This is the divine perspective from outside time applied to events that Israel must still walk out through seven days of marching. The same tension appears throughout OT and NT: God speaks of the elect as &ldquo;foreknown,&rdquo; of justification as already complete, of the resurrection as certain — while the historical unfolding remains ahead. Joshua 6:2 is the OT basis for speaking of future realities in the past tense of divine certainty.</p>",
    "3": "<p><strong>usbavtem et hair kol anshei hamilchamah</strong>: &lsquo;march around the city, all the men of war&rsquo; — military language (<em>anshei hamilchamah</em>, men of war) surrounds an operation involving no weapons: walking in circles while priests blow rams&rsquo; horns. The deliberate incongruity between military personnel and non-military action signals the point: this is YHWH&rsquo;s battle, not Israel&rsquo;s. The armies are present as participants in a divine act, not as agents of the victory. The same principle governs apostolic ministry: &ldquo;we do not wage war according to the flesh&rdquo; (2 Cor 10:3), but the weapons are not less powerful for being spiritual.</p>",
    "4": "<p><strong>shiva kohanim yisu shiva shofarot hayovelim</strong>: &lsquo;seven priests shall carry seven rams&rsquo; horns&rsquo; — the <em>shofar hayovel</em> (Jubilee horn) is distinct from the <em>chatsotsrot</em> (straight silver trumpets of Num 10). The <em>yovel</em> root connects to Jubilee (<em>yovel</em>, Lev 25) — the year of liberty and land-return. Whether intentional or not, the instrument announcing Jericho&rsquo;s fall is the instrument of liberation; YHWH&rsquo;s conquest is framed as a Jubilee-act, a reclaiming of the land from its temporary occupants. The sevenfold repetition (seven priests, seven horns, seven days, seven circuits) saturates the narrative with sabbatical completion.</p>",
    "5": "<p><strong>bimshoch beqeren hayovel bishmaachem et qol hashofar yaria chol haam</strong>: &lsquo;when they draw out the blast on the ram&rsquo;s horn, the whole people shall shout with a great shout&rsquo; — the sustained blast (<em>bimshoch</em>, drawing out the sound) precedes the corporate shout (<em>yaria</em>). The mechanics require the people to wait in silence through six days and then coordinate a single simultaneous shout. The obedient synchrony of the people&rsquo;s shout with the divine signal is the human act corresponding to divine action: the shout does not cause the walls to fall, but the walls fall at the shout.</p>",
    "6": "<p>Joshua&rsquo;s direct communication with the priests and army implements YHWH&rsquo;s command precisely. The detailed delegation — priests carry the ark, priests blow the horns, armed men march before and behind — creates a liturgical procession: ark-centered, priest-mediated, encompassed by armed men carrying no weapons against the city. This is the structure of biblical worship translated into military terms: the holy object at the center, priestly mediation, and the people surrounding it in ordered attention.</p>",
    "7": "<p><strong>ivru usubvu et hair</strong>: &lsquo;advance and march around the city&rsquo; — the Hebrew <em>avar</em> (cross over, advance) is the same verb used for Israel&rsquo;s crossing of the Jordan and for Israel&rsquo;s entry into the land generally. Every march around Jericho is a small <em>avar</em> — an act of crossing, passage, committed movement. The narrative is full of crossings: Jordan, Jericho, the land. Each individual crossing participates in the larger crossing-dynamic of the entire conquest.</p>",
    "8": "<p>The priests with their rams&rsquo; horns march before the ark, blowing continuously (<em>tamid taqea bataqoa hashofar</em>). The continual sounding is both a sonic claim on the territory — declaring YHWH&rsquo;s sovereignty by the Jubilee-instrument — and a liturgical frame within which the silent army marches. The silence of the army against the continual priestly music creates an unusual soundscape: worshipful proclamation surrounding military formation. This is not primarily a siege but a liturgy.</p>",
    "9": "<p><strong>hame'aseph holech acharei haaron</strong>: &lsquo;the rear guard came after the ark&rsquo; — the ark travels in the middle of the procession, with armed men ahead and a rear guard behind. This is the opposite of a normal military formation where the ark would be guarded at the rear; here the ark leads, and the military presence surrounds it as an escort. The spatial arrangement communicates: YHWH leads the battle; human forces are his retinue.</p>",
    "10": "<p><strong>lo taria velo tashmiu et qolchem</strong>: &lsquo;you shall not shout or make any sound with your voice&rsquo; — six days of absolute silence, broken only by priestly horns. The commanded silence is a discipline of waiting: Israel cannot shout until YHWH says to shout. The prohibition on premature noise is a prohibition on premature action — the very temptation Israel succumbed to at Massah and Meribah and at the golden calf. Silence before YHWH is a form of trust that his word and timing are sufficient.</p>",
    "11": "<p>Joshua executed the command precisely: a single circuit, return to camp, silence. The single-circuit days build expectation without providing discharge. Six days of partial action — enough to establish the pattern but not enough to produce the result. The daily manna, the weekly Sabbath, the annual Passover — all are repetitions building toward a final completion. Jericho&rsquo;s six days build toward the seventh day&rsquo;s seven circuits.</p>",
    "12": "<p><strong>vayashkem Yehoshua baboker</strong>: early rising — the same phrase used of Abraham rising early to obey YHWH&rsquo;s command regarding Isaac (Gen 22:3). Early rising as indicator of readiness and obedience is a minor but consistent motif: the one who has truly received a divine command does not delay its execution. The priests and ark are ready; the process begins again with the same fidelity as day one.</p>",
    "13": "<p>The repetition of seven priests with seven horns marching and blowing continually establishes the narrative as a liturgical cycle. The reader must inhabit the repetition, not skip past it. Six times the narrative rehearses the march, horn-blowing, silence, and return; the sixth repetition makes the seventh day&rsquo;s deviation — seven circuits instead of one — structurally explosive. The storyteller uses liturgical repetition to generate narrative momentum.</p>",
    "14": "<p>One circuit per day, silence, return to camp — the formula exactly repeated. The six-day structure recalls the six days of creation followed by the seventh day of completion. Jericho&rsquo;s fall on the seventh day after six days of preparation is structurally a Sabbath-pattern: what the preparation builds toward arrives on the day of rest and completion.</p>",
    "15": "<p><strong>bayom hashvii vayashkimu kaolot hashachar</strong>: &lsquo;on the seventh day they rose at the dawning of the day&rsquo; — the earliest possible start, the longest possible day. Seven circuits instead of one, beginning at dawn. The seventh day breaks the pattern established by days one through six in every dimension: earlier start, seven circuits, the shout that was forbidden now commanded. The Sabbath is the day when the pattern that seemed locked is broken open.</p>",
    "16": "<p><strong>bitoqa hashofar yaria hadam</strong>: &lsquo;at the trumpet blast, shout!&rsquo; — Joshua&rsquo;s command at the seventh blast of the seventh circuit connects action (shout) to divine signal (horn). The timing matters: not premature, not delayed, but synchronized with the divine signal. The shout is Israel&rsquo;s act of faith that YHWH&rsquo;s word has been fulfilled — they shout before the walls fall, trusting that the walls will fall. This is the structure of Heb 11:30: &ldquo;by faith the walls of Jericho fell down after they were encircled for seven days.&rdquo;</p>",
    "17": "<p><strong>tihyeh hair cherem hi vekol asher bah laYHWH</strong>: &lsquo;the city shall be a <em>cherem</em> — devoted to YHWH&rsquo; — <em>cherem</em> is the chapter&rsquo;s central theological term. It means something set apart entirely for YHWH, irrevocably consecrated, not for human use. The same root is used of things offered to the sanctuary that cannot be redeemed (Lev 27:28-29). For Jericho, <em>cherem</em> means total destruction: no survivors, no plunder, everything given to YHWH — destroyed (living things) or placed in the sanctuary treasury (precious metals). Jericho as the firstfruits city receives firstfruits treatment: everything holy, nothing retained.</p>",
    "18": "<p><strong>rak shemertu mihaacherem</strong>: &lsquo;but keep away from the devoted things&rsquo; — the warning about <em>cherem</em> contamination: taking any <em>cherem</em> object makes the entire camp <em>cherem</em>. The contamination is moral, not physical — the sin of treating what belongs to YHWH as available for personal use. The same principle governs the Lord&rsquo;s Supper: &ldquo;whoever eats the bread or drinks the cup of the Lord in an unworthy manner will be guilty of profaning the body and blood of the Lord&rdquo; (1 Cor 11:27) — treating the holy as ordinary brings judgment.</p>",
    "19": "<p><strong>kol kesef vezahav uklei nechoshet uvarzel qodesh hem laYHWH</strong>: &lsquo;all silver and gold and vessels of bronze and iron are sacred (<em>qodesh</em>) to YHWH&rsquo; — the precious metals are not destroyed but consecrated; they pass into YHWH&rsquo;s treasury as firstfruits of the conquest. Consistent with the principle that the first of everything belongs to YHWH (Exod 13:2): Jericho as the first city has its wealth wholly consecrated. Later cities allow plunder; this one does not.</p>",
    "20": "<p><strong>vayyari ham vayitqeu bashofarot vatipol hachomah tachhteha</strong>: &lsquo;the people shouted and the wall fell flat&rsquo; — grammatically, the people&rsquo;s shout and the wall&rsquo;s fall are juxtaposed but the wall&rsquo;s fall is in the passive: it fell, was caused to fall. The human action (shout) and the divine action (wall falls) are presented together without causal explanation. The gap between human act and divine result is preserved deliberately: this was YHWH&rsquo;s act in response to Israel&rsquo;s faith-act.</p>",
    "21": "<p><strong>vayacharimu et kol asher bair</strong>: &lsquo;they devoted to destruction all that was in the city&rsquo; — the execution of <em>cherem</em> against Jericho&rsquo;s population is among the most difficult passages in the OT. Several observations: (1) The Canaanite nations had been warned through four centuries of continued iniquity (Gen 15:16); (2) the narrative shows the way of escape was open — Rahab&rsquo;s household is saved; (3) the <em>cherem</em> is explicitly not ethnic but covenantal — the command targets religious contamination, not ethnicity (Deut 20:17-18). The theological issues require sustained engagement with divine character and purpose, not quick harmonization.</p>",
    "22": "<p>The spies are given their assignment: rescue Rahab as promised. The keeping of the oath given to a prostitute in a city subjected to <em>cherem</em> is itself remarkable: YHWH&rsquo;s people honor their word even in the chaos of total destruction. The specificity of the rescue (bring out the woman and all who belong to her, just as you swore) demonstrates covenant faithfulness in action: promises made are promises kept, regardless of circumstances.</p>",
    "23": "<p><strong>vayotziu et Rachav ve et aviha ve et imah ve et acheiha</strong>: &lsquo;they brought out Rahab, her father, mother, brothers, and all who belonged to her&rsquo; — the household salvation is complete. The promise in 2:18-19 was precisely this: all who are in your house will be saved. The inclusion of the entire household under her faith-act illustrates the household-salvation principle that reappears in Acts: &ldquo;believe in the Lord Jesus, and you will be saved, you and your household&rdquo; (Acts 16:31).</p>",
    "24": "<p><strong>veha'ir sarefu ba'esh</strong>: &lsquo;they burned the city with fire&rsquo; — the burning after the <em>cherem</em> is the physical completion of the consecration: what cannot be taken cannot remain. Archaeological evidence at Tell es-Sultan (likely ancient Jericho) includes extensive burning evidence at levels corresponding to the Late Bronze Age, though the exact stratigraphy remains contested. The silver, gold, and metals go to YHWH&rsquo;s treasury; everything else becomes ash.</p>",
    "25": "<p><strong>ve et Rachav hazonah ve et beit aviha ve et kol asher lah hecheyah Yehoshua</strong>: &lsquo;Joshua spared Rahab the prostitute, her father&rsquo;s household, and all who belonged to her&rsquo; — the explicit mention of her profession (<em>ha-zonah</em>) in the rescue verse is pointed: what determined her salvation was not social respectability but faith-expressing-itself-in-risk. Hebrews credits her by faith (Heb 11:31); James by works (Jas 2:25) — both are correct because her faith was expressed through her works. Matthew places her in the Messiah&rsquo;s genealogy (Matt 1:5).</p>",
    "26": "<p><strong>arur ha'ish lifnei YHWH asher yaqum uvana et hair hazot et Yericho</strong>: &lsquo;cursed before YHWH is the man who rises up and rebuilds this city Jericho&rsquo; — the rebuilding curse extends the <em>cherem</em>: because Jericho was devoted to YHWH, it must not be reclaimed for ordinary use. The specific curse formula (at the cost of his firstborn he lays its foundation, at the cost of his youngest son he sets up its gates) was fulfilled four centuries later: &ldquo;In his days Hiel of Bethel built Jericho. He laid its foundation at the cost of Abiram his firstborn, and set up its gates at the cost of his youngest son Segub, according to the word of the LORD that he spoke by Joshua&rdquo; (1 Kings 16:34).</p>",
    "27": "<p><strong>vayhi YHWH et Yehoshua vayhi shime'o bechol haAretz</strong>: &lsquo;the LORD was with Joshua, and his fame spread throughout the land&rsquo; — the divine presence formula used of Moses and of Israel generally. The spread of Joshua&rsquo;s fame is the reverse of Rahab&rsquo;s report (2:9-11): the nations heard and their hearts melted; after Jericho, that melting intensifies. The same power that kept YHWH&rsquo;s promise now makes YHWH&rsquo;s purpose known even to those who resist it.</p>"
  },
  "7": {
    "1": "<p><strong>vayim'alu vnei Yisrael ma'al bachareim</strong>: &lsquo;the sons of Israel committed a trespass (<em>ma'al</em>) regarding the devoted things&rsquo; — <em>ma'al</em> is a technical term for breach of faith specifically regarding sacred things: misappropriating what belongs to YHWH (cf. Lev 5:15). What makes this verse theologically striking is that YHWH&rsquo;s anger burned against Israel before the military defeat, before any human awareness of the sin. The hidden sin had already compromised the covenant relationship. Sin&rsquo;s effects are not dependent on its discovery.</p>",
    "2": "<p>Joshua sends spies to Ai (<em>ha-Ai</em>, the ruin) — the same intelligence-gathering approach as Jericho. The city&rsquo;s name (<em>Ai</em> = ruin) anticipates its fate: what is already a ruin will be made a permanent ruin after Achan&rsquo;s sin is dealt with. The scouts recommend a limited force — the same self-confidence that failed at Kadesh (Num 14:40-45) when Israel presumed on divine favor without divine command. Human military assessment without divine consultation is the structural error that Jericho&rsquo;s victory might have generated as a temptation.</p>",
    "3": "<p><strong>al yaal sham kol haam</strong>: &lsquo;not all the people need to go up&rsquo; — reasonable military calculation: why exhaust the whole army against a small target? But the calculation omits the variable that matters: YHWH&rsquo;s presence is not automatic. The assumption that victory follows from previous victory without consulting YHWH is the error. This is the warning of Deut 32:15 — prosperity can generate the self-reliance that forfeits divine presence.</p>",
    "4": "<p><strong>vayanusu mipnei anshei haAi</strong>: &lsquo;they fled before the men of Ai&rsquo; — described with the same vocabulary used of Canaanite fear before Israel (2:11; 5:1). Now the Israelites experience what they produced in their enemies: routed flight, melting hearts. The reversal is exact and painful. Israel defeated without YHWH is no different from any other nation; the divine presence, not ethnic identity or military prowess, was the only thing that made Israel different.</p>",
    "5": "<p><strong>vayyimas levav haam vayhi lemayim</strong>: &lsquo;the hearts of the people melted and became like water&rsquo; — this is the exact phrase Rahab used of Jericho (2:11: <em>vayimass levavchem</em>) and Joshua used of Canaanites (2:9). Israel is now experiencing what they inflicted on their enemies. The narrative symmetry is jarring: the people of God, living outside the covenant relationship, are as vulnerable to fear and defeat as the nations they were supposed to drive out.</p>",
    "6": "<p><strong>vayiqra Yehoshua simlotav vayipol al panav artzah lifnei aron YHWH</strong>: &lsquo;Joshua tore his garments and fell facedown before the ark of YHWH&rsquo; — mourning rites before the ark are appropriate responses to apparent divine abandonment, and they position Joshua correctly: before YHWH, seeking understanding. The elders pour dust on their heads — intensified mourning. The lament that follows is not faithless complaint but covenant-based questioning: YHWH brought us here; why would he abandon us? This is the form of Ps 44 and Lamentations — bold covenant appeal in the face of apparent divine failure.</p>",
    "7": "<p><strong>lama he'avarta he'avir et ha'am hazeh et hayarden</strong>: &lsquo;why did you bring this people across the Jordan at all?&rsquo; — Joshua&rsquo;s lament echoes the wilderness generation&rsquo;s complaint (Num 11:15; 14:3: &ldquo;it would have been better to die in Egypt&rdquo;). The similarity is deliberate: Joshua the leader, in his despair, sounds like the faithless people he replaced. Crisis produces regression to earlier complaints; even the greatest leaders can momentarily sound like those they lead.</p>",
    "8": "<p>Joshua&rsquo;s second lament: what can I say after Israel has turned tail? The concern is for the divine reputation — if Israel is defeated, what will YHWH&rsquo;s standing among the nations be? This is the same argument Moses used at the golden calf (Exod 32:12). The concern for divine honor in the eyes of the nations is not political spin but theological conviction: YHWH&rsquo;s name and Israel&rsquo;s fate are linked — when Israel fails, YHWH&rsquo;s faithfulness appears to fail with it.</p>",
    "9": "<p><strong>mah ta'aseh leshimcha hagadol</strong>: &lsquo;what will you do for your great name?&rsquo; — the appeal to divine self-interest is audacious but theologically precise: YHWH bound himself to Israel by covenant; Israel&rsquo;s destruction would reflect on the covenant-maker. Moses and Joshua both understand that covenant prayer can appeal to YHWH&rsquo;s own character and reputation. This is not manipulation but faith in the weight of the covenant bond.</p>",
    "10": "<p><strong>qum lecha lamah zeh attah nophel al panecha</strong>: &lsquo;Get up! Why are you lying on your face?&rsquo; — YHWH&rsquo;s response is brisk: the time for lament is over; the problem has a solution; stop grieving and act. The divine call from lament to action appears in Elijah&rsquo;s cave encounter (1 Kings 19:5) and in the NT: &ldquo;awake, O sleeper, and arise from the dead, and Christ will shine on you&rdquo; (Eph 5:14). Mourning without moving is not faithfulness.</p>",
    "11": "<p><strong>Yisrael chata vegam avru et briti asher tziviti otam</strong>: &lsquo;Israel has sinned and transgressed my covenant that I commanded them&rsquo; — YHWH&rsquo;s diagnosis is precise: the sin is corporate, it is a specific act (<em>lakchu min hacherem</em>, they took from the devoted things), and it is a covenant transgression. The corporate guilt for one man&rsquo;s sin raises the theological problem of collective responsibility (cf. Num 16:22: &ldquo;shall one man sin and you be angry at the whole congregation?&rdquo;). The community had not built in accountability structures to prevent <em>cherem</em> violation.</p>",
    "12": "<p><strong>lo tuchal bnei Yisrael laqum lifnei oyveihem</strong>: &lsquo;Israel cannot stand against their enemies&rsquo; — the connection between covenant sin and military inability is explicit. The <em>cherem</em> that was to be kept outside Israel has come inside it through Achan&rsquo;s act: Israel itself has become <em>cherem</em> (<em>hayiti lecharaim</em>). Sin makes the holy community its own enemy by importing into itself the thing it was commanded to destroy.</p>",
    "13": "<p><strong>qum qadesh et haam</strong>: &lsquo;arise, consecrate the people&rsquo; — YHWH&rsquo;s first command is preparation: consecrate before the investigation. The holiness-before-process sequence is consistent throughout: Sinai&rsquo;s consecration before the theophany (Exod 19:10-11), the priests&rsquo; purification before ministry. Access to divine process requires preparation of the community.</p>",
    "14": "<p><strong>veqaravtem laboqer leshivteihem</strong>: &lsquo;in the morning you shall be presented by tribes&rsquo; — the investigative lot-process narrows from tribe to clan to household to individual. The procedure is meticulous: YHWH does not simply name the culprit but walks Israel through a process that makes the identification certain and impossible to dispute. The lot system is not randomness but divine revelation (Prov 16:33: &ldquo;the lot is cast into the lap, but its every decision is from YHWH&rdquo;). Every level is exonerated by the process as it narrows.</p>",
    "15": "<p><strong>venivlah asah beYisrael</strong>: &lsquo;he has done folly (<em>nevalah</em>) in Israel&rsquo; — <em>nevalah</em> is a strong term typically associated with sexual immorality and sacrilege (Gen 34:7; 2 Sam 13:12). Its application to covenant theft is striking: taking the <em>cherem</em> is morally equivalent to sexual violation of the covenant community. The same category-mixing (sacrilege = violation) reveals how the OT understands the covenant as intimate relationship: breach of its terms is something close to sexual betrayal — hence the prophets&rsquo; repeated use of marital infidelity as the metaphor for idolatry.</p>",
    "16": "<p>The early-morning process begins: tribe by tribe before YHWH. The tribe of Judah is identified — the royal tribe from which the messianic line will come. The identification of the sinner within Judah does not taint the tribe permanently; David will come from Judah, and Achan&rsquo;s sin does not disqualify Judah from its messianic vocation. Individual sin does not determine tribal or corporate identity eternally.</p>",
    "17": "<p><strong>vayiqrev et mishpachat Yehudah vayilkod et mishpachat haZarchi</strong>: tribe (Judah), clan (Zerah), household (Zabdi), individual (Achan). The Zerah connection is pointed: Zerah was the twin son of Judah and Tamar (Gen 38:30) whose birth was marked by a scarlet thread — echoing Rahab&rsquo;s scarlet cord. In Judah&rsquo;s line, scarlet threads mark both salvation (Rahab, Zerah) and now judgment (Achan of Zerah&rsquo;s clan). The same family connection can carry either promise or condemnation depending on the individual&rsquo;s faithfulness.</p>",
    "18": "<p><strong>vayaqrev et beito lagvarim vayilkad Achan ben Carmi</strong>: &lsquo;he brought his household forward man by man, and Achan was taken&rsquo; — the final identification. The name Achan is connected by the narrative to <em>achar</em> (trouble) in v25 and to the Valley of Achor. The lot falls on one man after careful elimination, creating a publicly witnessed, undeniable identification: no appeal is possible — the process itself was YHWH&rsquo;s revelation.</p>",
    "19": "<p><strong>ten na kavod laYHWH Elohei Yisrael veten lo todah</strong>: &lsquo;give glory to YHWH God of Israel and praise him&rsquo; — Joshua&rsquo;s invitation to confess is framed as an act of worship: confessing sin is giving glory to God, acknowledging that YHWH is just and his judgment is right. The same formula appears in John 9:24 (Pharisees demand to the healed blind man: &ldquo;give glory to God&rdquo;) and Rev 14:7 (&ldquo;give glory to him, for the hour of his judgment has come&rdquo;). Confession as <em>gloria</em> is a consistent biblical structure.</p>",
    "20": "<p><strong>omen anochi chatati laYHWH Elohei Yisrael</strong>: &lsquo;it is true — I have sinned against YHWH God of Israel&rsquo; — the confession is direct and complete: <em>omen anochi</em> (truly it is I), <em>chatati</em> (I have sinned), addressed to YHWH. The sin is named theologically before it is described materially. This formal structure of confession — acknowledgment, theological framing, directed to God — is the model for genuine repentance throughout Scripture.</p>",
    "21": "<p><strong>va'ere bish'al adderet Shinar achat tovah vachmadem va'eqqachem</strong>: &lsquo;I saw… I coveted… I took&rsquo; — Achan&rsquo;s account follows the same three-step sequence as the first sin in Eden: saw (<em>vaere</em>), coveted (<em>vachmadem</em>), took (<em>va'eqqachem</em>). The verb <em>chamad</em> (covet) is the exact word of the tenth commandment (Exod 20:17: &ldquo;you shall not covet&rdquo;). Achan was not ignorant of the law; he performed the act prohibited in the commandment against coveting. The Babylonian cloak (<em>adderet Shinar</em>) — Shinar being Babylon — anticipates the Babylonian exile that will ultimately destroy what Jericho&rsquo;s fall began.</p>",
    "22": "<p>Joshua&rsquo;s men ran to the tent (<em>vayarutzu</em>, they ran) — urgency. Everything is exactly as Achan described: the cloak, the silver, the gold wedge, hidden in the tent with the silver underneath. The confession is verified by the evidence; the evidence matches the confession perfectly. The hidden things are found when sought: &ldquo;be sure your sin will find you out&rdquo; (Num 32:23) is the pattern operating here as throughout Scripture.</p>",
    "23": "<p><strong>vayiqachem mittoch ha'ohel vayavium el Yehoshua</strong>: &lsquo;they took the things from the tent and brought them to Joshua and all the Israelites&rsquo; — the public display of the hidden goods restores the contamination to visibility. The community must see what was hidden; the hidden sin must become public before the community can be restored. There is a consistent OT principle that sin&rsquo;s communal consequences require communal disclosure and judgment, not just private dealing.</p>",
    "24": "<p><strong>emek Achor</strong>: the transfer to the Valley of Achor (trouble) is precise: everything connected to the sin — the man, his household, his goods, and the goods he stole — is brought together for judgment. The naming of the valley creates a permanent memorial. Hosea later transforms this valley: &ldquo;I will make the Valley of Achor a door of hope&rdquo; (Hos 2:15) — the place of Israel&rsquo;s greatest corporate shame becomes the place of future restoration.</p>",
    "25": "<p><strong>mah avar'tanu</strong>: &lsquo;why have you troubled us?&rsquo; — the wordplay: <em>akar</em> (trouble) and <em>emek Achor</em> (Valley of Trouble). The name-to-fate technique creates a permanent linguistic memorial in the land&rsquo;s geography. Achan&rsquo;s execution by stoning and burning follows the <em>cherem</em>-contamination principle: what is contaminated by contact with <em>cherem</em> must be destroyed as <em>cherem</em>.</p>",
    "26": "<p><strong>vayashov YHWH mechamat apo</strong>: &lsquo;YHWH turned from his burning anger&rsquo; — the language of divine wrath and its turning is anthropopathic but structurally consistent: covenantal violation produces divine anger; covenantal justice produces the turning of that anger. The heap of stones over Achan creates a monument that will stand throughout Israel&rsquo;s history — and the valley that marked sin&rsquo;s judgment becomes, through divine grace, the threshold of restored covenant (Hos 2:15).</p>"
  },
  "8": {
    "1": "<p><strong>al tira ve'al techat</strong>: &lsquo;do not fear or be dismayed&rsquo; — YHWH&rsquo;s opening words to Joshua are the exact formula of the original commission (1:9). The repetition is deliberate: after the defeat at Ai and the Achan crisis, Joshua needs the commission renewed. Every new task in Joshua receives this divine declaration; the formula is not a one-time grant but a renewable resource. The same formula reaches its NT form in John 14:27: &ldquo;let not your hearts be troubled, neither let them be afraid.&rdquo;</p>",
    "2": "<p><strong>raq shallah uvehamatah tavzu lachem</strong>: &lsquo;only their plunder and livestock you shall take for yourselves&rsquo; — the key difference from Jericho: Ai is not <em>cherem</em>. The livestock and goods may be kept. This is YHWH&rsquo;s liberality after judgment: Jericho was the firstfruits city requiring total consecration; subsequent cities allow Israel to benefit. The first belongs entirely to YHWH; subsequent gifts may be used by the recipient.</p>",
    "3": "<p>Joshua chose capable warriors for the night ambush. The precision of the ambush strategy contrasts sharply with the cavalier two-to-three-thousand approach of the first Ai expedition (7:3-4). After Jericho and Achan, Joshua does not economize on military preparation. The strategy is explicitly commanded by YHWH (v2: &ldquo;set an ambush&rdquo;) — not improvised but divinely prescribed. Divine guidance does not replace careful planning but directs it.</p>",
    "4": "<p><strong>u'atem ta'arvu le'ir</strong>: &lsquo;set an ambush against the city&rsquo; — <em>erev</em> (ambush/lying in wait) in holy war is a legitimate instrument. The contrast with Jericho is complete: there, the conquest required seven days of public liturgical marching; here, it requires careful concealment and tactical surprise. The God who prescribed the Jericho liturgy also prescribes the Ai ambush — both are divine strategies.</p>",
    "5": "<p>Joshua&rsquo;s tactical explanation: they will advance toward Ai provoking the same response as before. The word <em>yaratzu</em> (they will run out) predicts the enemy&rsquo;s response precisely — not just tactical prediction but covenantal certainty: YHWH has said he will hand Ai over; the tactical plan operates within that certainty. Military planning and divine promise are not competing categories.</p>",
    "6": "<p><strong>ki yomeru nasoh nivchal milefaneihem</strong>: &lsquo;for they will say, &ldquo;They are fleeing before us, as before&rdquo;&rsquo; — the planned feigned retreat exploits Ai&rsquo;s memory of their previous victory. The king of Ai will repeat his successful strategy without recognizing that circumstances have changed. Those who have defeated God&rsquo;s people once become overconfident, and their overconfidence becomes the means of their destruction: Pharaoh pursued Israel into the Red Sea on the strength of his previous success.</p>",
    "7": "<p><strong>veatem taqumu min hama'arav</strong>: &lsquo;then you shall rise from the ambush and seize the city&rsquo; — the rising of the ambush force is timed to the moment when Ai&rsquo;s army is committed and cannot retreat. The ambush must hold still until the right moment; premature action would ruin the trap. Patience in waiting and decisiveness in acting are both required.</p>",
    "8": "<p><strong>ketsav et hair baesh ki dabar YHWH tasunu</strong>: &lsquo;set the city on fire — do this according to the word of YHWH&rsquo; — the fire is YHWH&rsquo;s command, not tactical improvisation. The burning of Ai is an act of covenantal judgment, not military vandalism.</p>",
    "9": "<p>The ambush force positioned itself between Bethel and Ai to the west. The specific geographic reference locates the action precisely in the central hill country. The ambush waits through the night — another discipline of delayed action: the force that will seize the city must wait in concealment until the tactical moment arrives. Premature action would have been as fatal as Achan&rsquo;s premature taking.</p>",
    "10": "<p><strong>vayashkem Yehoshua baboqer</strong>: early rising again (cf. 6:12; 7:16) — the consistent pattern of early morning readiness for divine action. Joshua reviewed the troops (<em>vayipqod</em>, he mustered them) then led the elders of Israel at the head of the army: the covenant leadership goes to battle together, not from the rear.</p>",
    "11": "<p>The main army took up position north of Ai with a valley between them and the city. The tactical geography is precise: the valley makes a direct assault obvious while requiring Ai&rsquo;s army to cross it to engage. The narrative attention to geography in chapters 6-12 is characteristic: the land is not a generic backdrop but a specific, named, remembered territory whose geography is woven into the memory of divine acts.</p>",
    "12": "<p>Five thousand men placed in ambush between Bethel and Ai to the west — a second ambush unit. The west/east positioning creates a pincer: the main army draws Ai eastward while the ambush takes the city from the west. The coordination required speaks to the discipline of the conquest force after the Achan crisis.</p>",
    "13": "<p>The positioning is complete: main force north, ambush west. Joshua went that night into the valley between the forces — commanders&rsquo; presence in the operational zone before the battle. Leadership is proximate to risk, not insulated from it.</p>",
    "14": "<p><strong>vayashkem melech haAi vayimalaru vayetze</strong>: &lsquo;when the king of Ai saw them, he hurried and went out&rsquo; — the verb <em>yishkimu</em> (they rose early, same root as Joshua&rsquo;s early rising) is pointed: Ai&rsquo;s king rises early to meet the threat, mirroring Joshua&rsquo;s early rising for obedience. The enemy is energetic and responsive — but his energy is deployed in the wrong direction because he does not know the ambush is behind him. Asymmetric knowledge of the full situation is what Joshua has and the king of Ai lacks.</p>",
    "15": "<p><strong>vayitnakkel Yehoshua vekol Yisrael lifneihem</strong>: &lsquo;Joshua and all Israel made themselves appear beaten before them&rsquo; — <em>vayitnakkel</em> is reflexive: they made themselves appear beaten. Deliberate performance, a tactical fiction in the service of YHWH&rsquo;s strategy. The tradition regards tactical stratagems as categorically different from prohibited deception; the Rahab narrative handled deception in service of YHWH&rsquo;s purposes without moral condemnation.</p>",
    "16": "<p><strong>vayizaqeu kol haam asher bair lirdof achareihem</strong>: &lsquo;all the people who were in the city were called out to pursue them&rsquo; — the complete emptying of Ai is the trap springing shut. The city is evacuated of its defenders; the ambush will walk into an undefended position. The king&rsquo;s initial success (routing the feint) becomes the mechanism of his total defeat.</p>",
    "17": "<p><strong>velo nish'ar ish beAi uveVeit El asher lo yatza acharei Yisrael</strong>: &lsquo;not a man was left in Ai or Bethel who had not gone out after Israel&rsquo; — Bethel&rsquo;s troops also committed to the pursuit. Total commitment to the wrong direction is total vulnerability to the right one. Forces totally committed to pursuing apparent advantage are exposed to the power that works precisely through what appears defeated.</p>",
    "18": "<p><strong>nteh bakidon asher beyadechu el haAi</strong>: &lsquo;point the javelin in your hand toward Ai&rsquo; — the extended spear deliberately echoes Moses&rsquo;s extended staff at Rephidim (Exod 17:11-12): &ldquo;whenever Moses held up his hand, Israel prevailed.&rdquo; Joshua&rsquo;s <em>kidon</em> (javelin) points toward Ai as Moses&rsquo;s staff pointed toward the battle. Both gestures are not magical but covenantal — visible expressions of dependence on YHWH&rsquo;s agency in the battle.</p>",
    "19": "<p><strong>vayaqumu hama'arav bimheram</strong>: &lsquo;the ambush rose quickly from their position&rsquo; — the force that waited through the night in disciplined stillness now acts with maximum speed (<em>bimheram</em>). Patience in waiting and decisiveness in acting are both required; the one who cannot hold still is as dangerous as the one who acts too late.</p>",
    "20": "<p><strong>vayyipenu anshei haAi achareihem vayyiru vehinneh alah ashan hair hashamayyim</strong>: &lsquo;the men of Ai looked back and saw the smoke from the city rising to the sky&rsquo; — the smoke is the visible sign that everything has gone wrong simultaneously: the city is captured behind them, they are committed too far forward to retreat, the feigned retreat is wheeling around to become an actual attack. Judgment often works this way: the moment of apparent escape is the moment the trap is most completely closed.</p>",
    "21": "<p><strong>vayar Yehoshua vekol Yisrael ki lakad hama'arav et hair</strong>: &lsquo;Joshua and all Israel saw that the ambush had captured the city&rsquo; — the smoke visible to both sides works differently on each: for Israel, the signal to turn and fight; for Ai, the signal that all is lost. The same event produces opposite responses depending on which side one is on. This is the consistent biblical pattern: divine acts are simultaneously redemptive and judgmental, life and death (2 Cor 2:15-16).</p>",
    "22": "<p><strong>vayihu Yisrael betoch</strong>: &lsquo;Israel was in their midst&rsquo; — the double encirclement is complete: main army attacking from the front and sides, ambush attacking from the rear, the men of the city trapped between. The word <em>betoch</em> (in the midst of) is the same used of YHWH&rsquo;s presence among Israel; the reversal is complete — Israel was surrounded and routed at 7:5; now Ai is surrounded and destroyed.</p>",
    "23": "<p><strong>ve et melech haAi tafsu chai</strong>: &lsquo;they captured the king of Ai alive&rsquo; — the single exception to total destruction: the king is taken alive for public execution by Joshua (v29). The king&rsquo;s public death before all Israel is both military demonstration and theological statement: the one who organized resistance to YHWH&rsquo;s purpose is publicly judged, not merely eliminated.</p>",
    "24": "<p><strong>vayyishvu kol Yisrael el haAi vayyakohu leftzi chariv</strong>: &lsquo;all Israel returned to Ai and struck it with the edge of the sword&rsquo; — the systematic completion of the battle follows the ambush&rsquo;s seizure of the city. What the first expedition failed to achieve through presumption is accomplished through obedience, divine strategy, and patient execution.</p>",
    "25": "<p><strong>kol hanoflim bayom hahu me'ish ve'ad ishah shemeim ashar alef</strong>: &lsquo;twelve thousand men and women fell that day — all the people of Ai&rsquo; — the death toll at Ai (12,000) far exceeds the initial Israelite defeat (36 dead, 7:5). The scale of the reversal is precise. The number twelve thousand — twelve tribes, thousands as the unit of military organization — may carry symbolic weight as representing a full tribal force.</p>",
    "26": "<p><strong>veYehoshua lo hashiv yado asher natah bakidon ad asher hechrim et kol yoshvei haAi</strong>: &lsquo;Joshua did not draw back his hand… until he had devoted all the inhabitants of Ai to destruction&rsquo; — the sustained extended arm is the explicit echo of Moses at Rephidim (Exod 17:12: &ldquo;his hands were steady until the going down of the sun&rdquo;). Moses held up his hands throughout the battle with Amalek; Joshua holds his spear extended throughout the battle with Ai. The sustained physical posture of the leader signifying sustained divine authority is a deliberate typological parallel: Joshua inheriting Moses&rsquo;s role enacted through the same bodily posture.</p>",
    "27": "<p><strong>raq habehemah ushlal hair hazot bazazu lahem Yisrael kadvar YHWH</strong>: &lsquo;only the livestock and plunder of Ai Israel took for themselves — as YHWH commanded Joshua&rsquo; — the explicit contrast with Jericho: the same act that was <em>cherem</em>-violation at Jericho is covenant-obedience at Ai. The moral valence of an action depends not only on the action itself but on whether YHWH has permitted or prohibited it. Achan took what YHWH had kept sacred; Israel takes at Ai what YHWH has released.</p>",
    "28": "<p><strong>vayyisrof Yehoshua et haAi vaysiymehah tel olam shemamah</strong>: &lsquo;Joshua burned Ai and made it a <em>tel olam</em> — a permanent ruin&rsquo; — <em>tel olam</em> (forever-mound) is the origin of the archaeological term <em>tell</em>: a mound of accumulated ruins marking a destroyed city. The word <em>olam</em> (forever) makes the destruction permanent and deliberate; Ai will not be rebuilt for ordinary habitation. The destroyed cities leave permanent marks in the terrain as ongoing testimonies to the conquest.</p>",
    "29": "<p><strong>ve et melech haAi talah al ha-etz</strong>: &lsquo;the king of Ai he hanged on a tree&rsquo; — execution by hanging invokes Deut 21:23: &ldquo;a hanged man is cursed by God.&rdquo; The king dies under the covenant curse. The sunset-burial requirement (Deut 21:23) is observed. Paul applies the Deut 21:23 curse-formula to Christ&rsquo;s death (Gal 3:13: &ldquo;Christ redeemed us from the curse of the law by becoming a curse for us — for it is written, &lsquo;Cursed is everyone who is hanged on a tree&rsquo;&rdquo;). The king of Ai died as a cursed man; Christ died as the one who became the curse for others.</p>",
    "30": "<p><strong>az yivneh Yehoshua mizbeach laYHWH Elohei Yisrael behar Eval</strong>: &lsquo;then Joshua built an altar to YHWH God of Israel on Mount Ebal&rsquo; — the altar-building on Ebal immediately follows the conquest of Ai, before the conquest of the southern or northern territories. The sequence is deliberate: conquest leads to covenant renewal, not to further conquest. The altar on Ebal was commanded by Moses (Deut 27:4-8) as the first act upon entering the land.</p>",
    "31": "<p><strong>kazasher tzivah Moshe eved YHWH livnei Yisrael kakatuv besefer torat Moshe</strong>: &lsquo;as Moses the servant of YHWH had commanded… as written in the Book of the Law of Moses&rsquo; — the altar is built exactly as specified: unhewn stones, no iron tool (cf. Exod 20:25: hewn stone would impose human craft on what is offered to YHWH). The altar&rsquo;s simplicity is theological: YHWH does not require human artistry to make his altar acceptable. Contrast with the elaborate metalwork of the tabernacle; the Ebal altar is deliberate simplicity for a specific purpose.</p>",
    "32": "<p><strong>vayiktov sham al ha'avanim et mishneh torat Moshe</strong>: &lsquo;he wrote on the stones a copy of the Law of Moses&rsquo; — the Torah inscribed on stones at the moment of land-entry creates a visible, permanent record of the covenant obligation governing the land&rsquo;s use. The inscribed Torah on Ebal&rsquo;s stones anticipates the new covenant&rsquo;s inscription: &ldquo;I will put my law within them, and I will write it on their hearts&rdquo; (Jer 31:33).</p>",
    "33": "<p><strong>vehager</strong>: &lsquo;and the resident alien&rsquo; — the covenant assembly at Ebal and Gerizim explicitly includes the <em>ger</em> (resident alien) alongside the native-born Israelite. The inclusion of sojourners in the covenant assembly is remarkable: the Sinai covenant was given to Israel, but at the first renewal ceremony in the land, non-Israelite residents are included. The universality latent in the Abrahamic covenant (Gen 12:3) begins to manifest at Ebal: the covenant community is expanding, not contracting, in the land.</p>",
    "34": "<p><strong>veachar qara et kol divrei hatorah habrachah vehaqelalah</strong>: &lsquo;afterward he read all the words of the Law, the blessings and the curses&rsquo; — the full public reading of Deut 27-28 in the land, with the entire community assembled, creates a formal covenant ratification. The blessings and curses are read aloud before all Israel: the community enters the land as a covenant community fully informed of its obligations and consequences. The transparency of the covenant terms — public, inclusive, comprehensive — means no one can claim ignorance of what was at stake.</p>",
    "35": "<p><strong>lo hayah davar mikol asher tzivah Moshe asher lo qara Yehoshua</strong>: &lsquo;there was not a word of all that Moses commanded that Joshua did not read before the assembly&rsquo; — total comprehensiveness: every word, nothing omitted. Women, little children, and resident aliens were all included — every member of the community heard the complete Torah. The fullness-of-revelation principle: the covenant community receives the full disclosure of what God requires and what God promises. The church&rsquo;s obligation is the same: &ldquo;the whole counsel of God&rdquo; (Acts 20:27), not a curated selection.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'joshua')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'joshua', c)
    print('joshua ch 6-8: mkt-original written')

if __name__ == '__main__':
    main()
